use crate::pleromatic_frame::PleromaticFrame;
use std::fs;

/// Knot Storage: Persistent archive for Pleromatic frames.
///
/// Handles the commitment of "high-energy" frames (NOAA images,
/// significant IoT residue, coordinated swarm signals) to the
/// local filesystem as `.knot` files.
pub struct KnotStorage {
    root: String,
}

impl KnotStorage {
    /// Create a new KnotStorage at the specified root directory.
    pub fn new(root: &str) -> Self {
        fs::create_dir_all(root).ok();
        Self {
            root: root.to_string(),
        }
    }

    /// Archive a frame to disk.
    /// Returns the path to the saved frame on success.
    pub fn archive(&self, frame: &PleromaticFrame) -> std::io::Result<String> {
        let filename = format!(
            "{}/{}_{:05}.frame",
            self.root,
            frame.timestamp_ms,
            frame.seq % 100000
        );
        let bytes = bincode::serialize(frame)
            .map_err(std::io::Error::other)?;
        fs::write(&filename, bytes)?;
        Ok(filename)
    }

    /// Retrieve the most recent archived frame.
    pub fn latest_frame(&self) -> std::io::Result<Option<PleromaticFrame>> {
        let entries = fs::read_dir(&self.root)?;
        let mut paths: Vec<_> = entries
            .flatten()
            .filter(|e| e.path().extension().is_some_and(|ext| ext == "frame"))
            .map(|e| e.path())
            .collect();

        paths.sort(); // Sort by filename (timestamp_seq)

        if let Some(last) = paths.last() {
            let bytes = fs::read(last)?;
            let frame = bincode::deserialize(&bytes)
                .map_err(std::io::Error::other)?;
            Ok(Some(frame))
        } else {
            Ok(None)
        }
    }

    /// Prune old frames to stay under a specific capacity.
    pub fn prune(&self, max_files: usize) -> std::io::Result<()> {
        let entries = fs::read_dir(&self.root)?;
        let mut paths: Vec<_> = entries
            .flatten()
            .filter(|e| e.path().extension().is_some_and(|ext| ext == "frame"))
            .map(|e| e.path())
            .collect();

        paths.sort(); // Sort by filename (timestamp_seq)

        if paths.len() > max_files {
            let to_delete = paths.len() - max_files;
            for path in paths.iter().take(to_delete) {
                fs::remove_file(path).ok();
            }
        }
        Ok(())
    }

    /// Retrieve the N most recent archived frames.
    pub fn history(&self, limit: usize) -> std::io::Result<Vec<PleromaticFrame>> {
        let entries = fs::read_dir(&self.root)?;
        let mut paths: Vec<_> = entries
            .flatten()
            .filter(|e| e.path().extension().is_some_and(|ext| ext == "frame"))
            .map(|e| e.path())
            .collect();

        paths.sort();

        let mut frames = Vec::new();
        for path in paths.iter().rev().take(limit) {
            let bytes = fs::read(path)?;
            if let Ok(frame) = bincode::deserialize::<PleromaticFrame>(&bytes) {
                frames.push(frame);
            }
        }
        Ok(frames)
    }
}
